import{_ as n,c as t,o as a,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Quick Start: Install DCP Plugin | opencode-dynamic-context-pruning","description":"Learn how to install the OpenCode DCP plugin in 5 minutes. Configure the plugin, verify installation, and see immediate token savings through automatic deduplication and AI-driven pruning.","frontmatter":{"title":"Quick Start: Install DCP Plugin | opencode-dynamic-context-pruning","sidebarTitle":"Quick Start","subtitle":"Installation and Quick Start","description":"Learn how to install the OpenCode DCP plugin in 5 minutes. Configure the plugin, verify installation, and see immediate token savings through automatic deduplication and AI-driven pruning.","tags":["Installation","Quick Start","DCP"],"prerequisite":["OpenCode installed"],"order":1},"headers":[],"relativePath":"Opencode-DCP/opencode-dynamic-context-pruning/start/getting-started/index.md","filePath":"Opencode-DCP/opencode-dynamic-context-pruning/start/getting-started/index.md"}'),i={name:"Opencode-DCP/opencode-dynamic-context-pruning/start/getting-started/index.md"};function s(l,e,r,c,p,d){return a(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="installation-and-quick-start" tabindex="-1">Installation and Quick Start <a class="header-anchor" href="#installation-and-quick-start" aria-label="Permalink to &quot;Installation and Quick Start&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>✅ Complete DCP plugin installation in 5 minutes</li><li>✅ Configure the plugin and verify successful installation</li><li>✅ See your first automatic pruning in action</li></ul><h2 id="your-current-challenge" tabindex="-1">Your Current Challenge <a class="header-anchor" href="#your-current-challenge" aria-label="Permalink to &quot;Your Current Challenge&quot;">​</a></h2><p>After using OpenCode for a while, your conversations get longer:</p><ul><li>AI reads the same file multiple times</li><li>Tool error messages clutter your context</li><li>Each conversation consumes a large number of tokens</li><li><strong>Longer conversations = slower AI responses</strong></li></ul><p>You want to automatically clean up redundant content in conversations without manual intervention.</p><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p><strong>DCP (Dynamic Context Pruning)</strong> is an OpenCode plugin that automatically removes redundant tool calls from conversation history, reducing token consumption.</p><p>How it works:</p><ol><li><strong>Automatic Detection</strong>: Analyzes conversation history before each message is sent</li><li><strong>Intelligent Cleanup</strong>: Removes duplicate tool calls, stale errors, and overwritten writes</li><li><strong>AI-Driven</strong>: AI can actively call <code>discard</code> and <code>extract</code> tools to optimize context</li><li><strong>Transparent and Controllable</strong>: View pruning statistics via <code>/dcp</code> command, manually trigger cleanup</li></ol><div class="tip custom-block"><p class="custom-block-title">Key Advantages</p><ul><li><strong>Zero Cost</strong>: Automatic strategies require no LLM calls</li><li><strong>Zero Configuration</strong>: Works out of the box with optimized defaults</li><li><strong>Zero Risk</strong>: Only modifies context sent to LLM, conversation history remains unchanged</li></ul></div><h2 id="🎒-prerequisites" tabindex="-1">🎒 Prerequisites <a class="header-anchor" href="#🎒-prerequisites" aria-label="Permalink to &quot;🎒 Prerequisites&quot;">​</a></h2><p>Before starting, ensure:</p><ul><li>[ ] <strong>OpenCode</strong> is installed (with plugin support)</li><li>[ ] You know how to edit <strong>OpenCode configuration file</strong></li><li>[ ] You understand basic <strong>JSONC syntax</strong> (JSON with comments)</li></ul><div class="warning custom-block"><p class="custom-block-title">Important Note</p><p>DCP modifies the context content sent to the LLM but does not affect your conversation history. You can disable the plugin in your configuration at any time.</p></div><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-edit-opencode-configuration-file" tabindex="-1">Step 1: Edit OpenCode Configuration File <a class="header-anchor" href="#step-1-edit-opencode-configuration-file" aria-label="Permalink to &quot;Step 1: Edit OpenCode Configuration File&quot;">​</a></h3><p><strong>Why</strong> You need to declare the DCP plugin in your OpenCode configuration so OpenCode automatically loads it on startup.</p><p>Open your OpenCode configuration file <code>opencode.jsonc</code> and add DCP to the <code>plugin</code> field:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// opencode.jsonc</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@tarquinen/opencode-dcp@latest&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>You should see</strong>: The configuration file may have other plugins (if any), just add DCP at the end of the array.</p><div class="info custom-block"><p class="custom-block-title">Tip</p><p>Using the <code>@latest</code> tag ensures OpenCode automatically checks and fetches the latest version on startup.</p></div><h3 id="step-2-restart-opencode" tabindex="-1">Step 2: Restart OpenCode <a class="header-anchor" href="#step-2-restart-opencode" aria-label="Permalink to &quot;Step 2: Restart OpenCode&quot;">​</a></h3><p><strong>Why</strong> Plugin configuration changes require a restart to take effect.</p><p>Completely close OpenCode, then restart it.</p><p><strong>You should see</strong>: OpenCode starts normally without any error messages.</p><h3 id="step-3-verify-plugin-installation" tabindex="-1">Step 3: Verify Plugin Installation <a class="header-anchor" href="#step-3-verify-plugin-installation" aria-label="Permalink to &quot;Step 3: Verify Plugin Installation&quot;">​</a></h3><p><strong>Why</strong> Confirm that the DCP plugin is loaded correctly and view the default configuration.</p><p>In an OpenCode conversation, enter:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/dcp</span></span></code></pre></div><p><strong>You should see</strong>: DCP command help information, indicating the plugin was installed successfully.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Commands                         │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  /dcp context      Show token usage breakdown for current session</span></span>
<span class="line"><span>  /dcp stats        Show DCP pruning statistics</span></span>
<span class="line"><span>  /dcp sweep [n]    Prune tools since last user message, or last n tools</span></span></code></pre></div><h3 id="step-4-check-default-configuration" tabindex="-1">Step 4: Check Default Configuration <a class="header-anchor" href="#step-4-check-default-configuration" aria-label="Permalink to &quot;Step 4: Check Default Configuration&quot;">​</a></h3><p><strong>Why</strong> Understand DCP&#39;s default configuration and confirm the plugin works as expected.</p><p>DCP automatically creates a configuration file on first run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># View global configuration file</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/opencode/dcp.jsonc</span></span></code></pre></div><p><strong>You should see</strong>: Configuration file created with only the <code>$schema</code> field initially:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;$schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://raw.githubusercontent.com/Opencode-DCP/opencode-dynamic-context-pruning/master/dcp.schema.json&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>The configuration file initially contains only the <code>$schema</code> field. All other configuration items use code defaults, requiring no manual configuration.</p><div class="tip custom-block"><p class="custom-block-title">Default Configuration Explained</p><p>DCP&#39;s code defaults (no need to write to config file):</p><ul><li><strong>deduplication</strong>: Automatic deduplication, removes duplicate tool calls</li><li><strong>purgeErrors</strong>: Automatically cleans error tool inputs from 4 turns ago</li><li><strong>discard/extract</strong>: AI-callable pruning tools</li><li><strong>pruneNotification</strong>: Displays detailed pruning notifications</li></ul><p>If you need custom configuration, you can manually add these fields. See <a href="./../configuration/">Configuration Guide</a> for details.</p></div><h3 id="step-5-experience-automatic-pruning" tabindex="-1">Step 5: Experience Automatic Pruning <a class="header-anchor" href="#step-5-experience-automatic-pruning" aria-label="Permalink to &quot;Step 5: Experience Automatic Pruning&quot;">​</a></h3><p><strong>Why</strong> Use DCP in practice and see automatic pruning results.</p><p>Have a conversation in OpenCode where the AI reads the same file multiple times or executes tool calls that will fail.</p><p><strong>You should see</strong>:</p><ol><li>DCP automatically analyzes conversation history before each message is sent</li><li>If there are duplicate tool calls, DCP automatically cleans them up</li><li>After AI responds, you may see pruning notifications (depending on <code>pruneNotification</code> configuration)</li></ol><p>Example pruning notification:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>▣ DCP | ~12.5K tokens saved total</span></span>
<span class="line"><span></span></span>
<span class="line"><span>▣ Pruning (~12.5K tokens)</span></span>
<span class="line"><span>→ read: src/config.ts</span></span>
<span class="line"><span>→ write: package.json</span></span></code></pre></div><p>Enter <code>/dcp context</code> to view current session token usage:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Session Context Breakdown:</span></span>
<span class="line"><span>──────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System         15.2% │████████████████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│  25.1K tokens</span></span>
<span class="line"><span>User            5.1% │████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│   8.4K tokens</span></span>
<span class="line"><span>Assistant       35.8% │██████████████████████████████████████▒▒▒▒▒▒▒│  59.2K tokens</span></span>
<span class="line"><span>Tools (45)      43.9% │████████████████████████████████████████████████│  72.6K tokens</span></span>
<span class="line"><span></span></span>
<span class="line"><span>──────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Summary:</span></span>
<span class="line"><span>  Pruned:          12 tools (~15.2K tokens)</span></span>
<span class="line"><span>  Current context: ~165.3K tokens</span></span>
<span class="line"><span>  Without DCP:     ~180.5K tokens</span></span></code></pre></div><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><p>After completing these steps, you should:</p><ul><li>[ ] Added DCP plugin to <code>opencode.jsonc</code></li><li>[ ] OpenCode restarts and runs normally</li><li>[ ] <code>/dcp</code> command displays help information</li><li>[ ] Configuration file <code>~/.config/opencode/dcp.jsonc</code> is created</li><li>[ ] Can see pruning notifications in conversations or view pruning statistics via <code>/dcp context</code></li></ul><p><strong>If a step fails</strong>:</p><ul><li>Check if <code>opencode.jsonc</code> syntax is correct (JSONC format)</li><li>Check OpenCode logs for plugin loading errors</li><li>Confirm OpenCode version supports plugin functionality</li></ul><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="issue-1-plugin-not-working" tabindex="-1">Issue 1: Plugin Not Working <a class="header-anchor" href="#issue-1-plugin-not-working" aria-label="Permalink to &quot;Issue 1: Plugin Not Working&quot;">​</a></h3><p><strong>Symptom</strong>: Configuration added but no pruning effects visible</p><p><strong>Cause</strong>: OpenCode not restarted or incorrect config file path</p><p><strong>Solution</strong>:</p><ol><li>Completely close OpenCode and restart</li><li>Check if <code>opencode.jsonc</code> location is correct</li><li>Check logs: log files in <code>~/.config/opencode/logs/dcp/daily/</code> directory</li></ol><h3 id="issue-2-configuration-file-not-created" tabindex="-1">Issue 2: Configuration File Not Created <a class="header-anchor" href="#issue-2-configuration-file-not-created" aria-label="Permalink to &quot;Issue 2: Configuration File Not Created&quot;">​</a></h3><p><strong>Symptom</strong>: <code>~/.config/opencode/dcp.jsonc</code> does not exist</p><p><strong>Cause</strong>: OpenCode hasn&#39;t called DCP plugin or config directory permission issues</p><p><strong>Solution</strong>:</p><ol><li>Confirm OpenCode has been restarted</li><li>Manually create config directory: <code>mkdir -p ~/.config/opencode</code></li><li>Check plugin name in <code>opencode.jsonc</code>: <code>@tarquinen/opencode-dcp@latest</code></li></ol><h3 id="issue-3-pruning-notifications-not-displayed" tabindex="-1">Issue 3: Pruning Notifications Not Displayed <a class="header-anchor" href="#issue-3-pruning-notifications-not-displayed" aria-label="Permalink to &quot;Issue 3: Pruning Notifications Not Displayed&quot;">​</a></h3><p><strong>Symptom</strong>: No pruning notifications visible, but <code>/dcp stats</code> shows pruning occurred</p><p><strong>Cause</strong>: <code>pruneNotification</code> configured as <code>&quot;off&quot;</code> or <code>&quot;minimal&quot;</code></p><p><strong>Solution</strong>: Modify configuration file:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pruneNotification&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;detailed&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // or &quot;minimal&quot;</span></span></code></pre></div><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Installing the DCP plugin is very simple:</p><ol><li>Add plugin to <code>opencode.jsonc</code></li><li>Restart OpenCode</li><li>Use <code>/dcp</code> command to verify installation</li><li>Default configuration works without additional adjustments</li></ol><p><strong>DCP&#39;s default enabled features</strong>:</p><ul><li>✅ Automatic deduplication strategy (removes duplicate tool calls)</li><li>✅ Error cleanup strategy (cleans stale error inputs)</li><li>✅ AI-driven tools (<code>discard</code> and <code>extract</code>)</li><li>✅ Detailed pruning notifications</li></ul><p><strong>Next Step</strong>: Learn how to customize configuration to adjust pruning strategies for different scenarios.</p><hr><h2 id="coming-up-next" tabindex="-1">Coming Up Next <a class="header-anchor" href="#coming-up-next" aria-label="Permalink to &quot;Coming Up Next&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../configuration/">Configuration Guide</a></strong></p><p>You&#39;ll learn:</p><ul><li>Multi-level configuration system (global, environment variables, project-level)</li><li>All configuration options and recommended settings</li><li>Turn protection, protected tools, and protected file patterns</li><li>How to enable/disable different pruning strategies</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Range</th></tr></thead><tbody><tr><td>Plugin Entry</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/index.ts" target="_blank" rel="noreferrer"><code>index.ts</code></a></td><td>12-102</td></tr><tr><td>Config Manager</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/config.ts" target="_blank" rel="noreferrer"><code>lib/config.ts</code></a></td><td>669-794</td></tr><tr><td>Command Handler</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/help.ts" target="_blank" rel="noreferrer"><code>lib/commands/help.ts</code></a></td><td>1-40</td></tr><tr><td>Token Calculator</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/context.ts" target="_blank" rel="noreferrer"><code>lib/commands/context.ts</code></a></td><td>68-174</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li><code>MAX_TOOL_CACHE_SIZE = 1000</code>: Maximum number of tool cache entries</li></ul><p><strong>Key Functions</strong>:</p><ul><li><code>Plugin()</code>: Plugin registration and hook setup</li><li><code>getConfig()</code>: Load and merge multi-level configuration</li><li><code>handleContextCommand()</code>: Analyze current session token usage</li></ul></details>`,83)])])}const h=n(i,[["render",s]]);export{g as __pageData,h as default};
